let animals = [];
let plants = [];
let sun;
let clouds = [];
let soil;

function setup() {
  createCanvas(800, 500);
  textAlign(CENTER, CENTER);

  // Create sky gradient
  skyGradient = createGraphics(width, height);
  for (let i = 0; i < height; i++) {
    let inter = map(i, 0, height, 0, 1);
    let c = lerpColor(color(135, 206, 235), color(255, 255, 255), inter);
    skyGradient.noStroke();
    skyGradient.fill(c);
    skyGradient.rect(0, i, width, 1);
  }

  // Create soil
  soil = createGraphics(width, 100);
  soil.fill(101, 67, 33);
  soil.rect(0, 0, width, 100);
  soil.fill(139, 69, 19);
  for (let i = 0; i < 30; i++) {
    let x = random(width);
    let y = random(20, 80);
    soil.ellipse(x, y, random(5, 15), random(3, 8));
  }

  // Create sun
  sun = new Sun(700, 80);

  // Create clouds
  for (let i = 0; i < 3; i++) {
    clouds.push(new Cloud(random(100, 600), random(50, 120)));
  }

  // Create animals
  animals.push(new Rabbit(150, 350));
  animals.push(new Butterfly(400, 200));
  animals.push(new Bird(600, 150));

  // Create plants
  plants.push(new Flower(200, 400, 'red'));
  plants.push(new Flower(350, 420, 'yellow'));
  plants.push(new Tree(550, 380));
  plants.push(new Flower(650, 410, 'pink'));
}

function draw() {
  image(skyGradient, 0, 0);

  // Draw sun
  sun.display();
  sun.animate();

  // Draw clouds
  for (let cloud of clouds) {
    cloud.display();
    cloud.animate();
  }

  // Draw ground
  image(soil, 0, height - 100);

  // Draw grass
  noStroke();
  for (let i = 0; i < width; i += 5) {
    let grassHeight = random(8, 18);
    fill(34, 139, 34);
    triangle(i, height - 100, i + 2, height - 100 - grassHeight, i + 4, height - 100);
  }

  // Draw plants (behind animals)
  for (let plant of plants) {
    plant.display();
  }

  // Draw animals
  for (let animal of animals) {
    animal.display();
    animal.animate();
  }

  // Title and instructions
  fill(50);
  textSize(28);
  textFont('Comic Sans MS');
  text('🐰 Living Things 🦋', width / 2, 40);

  textSize(14);
  fill(80);
  text('Click on animals to see them move!', width / 2, height - 15);
}

function mousePressed() {
  for (let animal of animals) {
    if (animal.contains(mouseX, mouseY)) {
      animal.interact();
    }
  }
}

