class Sun {
  constructor(x, y) {
    this.x = x;
    this.y = y;
    this.rays = 12;
  }

  display() {
    push();
    // Rays
    stroke(255, 200, 50, 150);
    strokeWeight(3);
    for (let i = 0; i < this.rays; i++) {
      let angle = (TWO_PI / this.rays) * i + frameCount * 0.01;
      let inner = 35;
      let outer = 50;
      line(this.x + cos(angle) * inner, this.y + sin(angle) * inner,
           this.x + cos(angle) * outer, this.y + sin(angle) * outer);
    }
    // Sun body
    noStroke();
    fill(255, 220, 50);
    ellipse(this.x, this.y, 50, 50);
    fill(255, 250, 150);
    ellipse(this.x, this.y, 35, 35);
    pop();
  }

  animate() {
    // Gentle pulsing
  }
}

class Cloud {
  constructor(x, y) {
    this.x = x;
    this.y = y;
    this.speed = random(0.2, 0.5);
  }

  display() {
    fill(255, 255, 255, 230);
    noStroke();
    ellipse(this.x, this.y, 60, 35);
    ellipse(this.x - 25, this.y + 5, 45, 30);
    ellipse(this.x + 25, this.y + 5, 45, 30);
    ellipse(this.x + 10, this.y - 10, 40, 25);
  }

  animate() {
    this.x += this.speed;
    if (this.x > width + 50) this.x = -50;
  }
}

class Rabbit {
  constructor(x, y) {
    this.x = x;
    this.y = y;
    this.baseX = x;
    this.size = 50;
    this.hopOffset = 0;
    this.isHopping = false;
    this.hopTimer = 0;
  }

  display() {
    push();
    translate(this.x, this.y - this.hopOffset);

    // Body
    fill(220, 220, 220);
    ellipse(0, 0, this.size, this.size * 0.8);

    // Head
    ellipse(15, -10, 30, 25);

    // Ears
    fill(255, 200, 200);
    ellipse(10, -30, 8, 25);
    ellipse(20, -30, 8, 25);
    fill(220, 220, 220);
    ellipse(10, -30, 5, 18);
    ellipse(20, -30, 5, 18);

    // Eyes
    fill(0);
    ellipse(20, -12, 4, 4);

    // Nose
    fill(255, 150, 150);
    ellipse(28, -8, 5, 4);

    // Tail
    fill(255);
    ellipse(-20, 5, 12, 10);

    pop();
  }

  animate() {
    if (this.isHopping) {
      this.hopOffset = sin(this.hopTimer) * 20;
      this.hopTimer += 0.3;
      if (this.hopTimer > PI) {
        this.isHopping = false;
        this.hopOffset = 0;
        this.x = this.baseX;
      }
    } else {
      // Idle breathing
      this.size = 50 + sin(frameCount * 0.1) * 2;
    }
  }

  interact() {
    this.isHopping = true;
    this.hopTimer = 0;
    this.baseX = this.x;
    this.x += random(-80, 80);
  }

  contains(mx, my) {
    return dist(mx, my, this.x, this.y) < 40;
  }
}

class Butterfly {
  constructor(x, y) {
    this.x = x;
    this.y = y;
    this.baseX = x;
    this.baseY = y;
    this.wingAngle = 0;
    this.isFlying = false;
    this.flyTimer = 0;
  }

  display() {
    push();
    translate(this.x, this.y);

    // Wings
    let wing flap = sin(this.wingAngle) * 0.5;

    fill(255, 100, 150);
    push();
    rotate(flap);
    ellipse(-10, 0, 25, 35);
    pop();
    push();
    rotate(-flap);
    ellipse(10, 0, 25, 35);
    pop();

    // Wing patterns
    fill(255, 200, 50);
    ellipse(-8, -5, 8, 8);
    ellipse(8, -5, 8, 8);

    // Body
    fill(50, 30, 10);
    ellipse(0, 0, 6, 25);

    // Antennae
    stroke(50, 30, 10);
    strokeWeight(1);
    noFill();
    arc(-3, -10, 8, 15, -PI, 0);
    arc(3, -10, 8, 15, -PI, 0);

    pop();
  }

  animate() {
    this.wingAngle += 0.4;

    if (this.isFlying) {
      this.x = this.baseX + sin(this.flyTimer) * 80;
      this.y = this.baseY + cos(this.flyTimer * 0.7) * 40;
      this.flyTimer += 0.05;
      if (this.flyTimer > TWO_PI * 3) {
        this.isFlying = false;
        this.x = this.baseX;
        this.y = this.baseY;
      }
    }
  }

  interact() {
    this.isFlying = true;
    this.flyTimer = 0;
  }

  contains(mx, my) {
    return dist(mx, my, this.x, this.y) < 30;
  }
}

class Bird {
  constructor(x, y) {
    this.x = x;
    this.y = y;
    this.baseX = x;
    this.baseY = y;
    this.isFlying = false;
    this.flyTimer = 0;
    this.wingAngle = 0;
  }

  display() {
    push();
    translate(this.x, this.y);

    let wingFlap = sin(this.wingAngle) * 0.4;

    // Wings
    fill(70, 130, 180);
    push();
    rotate(wingFlap);
    ellipse(-15, 0, 25, 15);
    pop();
    push();
    rotate(-wingFlap);
    ellipse(15, 0, 25, 15);
    pop();

    // Body
    fill(255, 200, 100);
    ellipse(0, 0, 30, 20);

    // Head
    ellipse(12, -5, 15, 12);

    // Beak
    fill(255, 150, 50);
    triangle(18, -5, 28, -3, 18, 0);

    // Eye
    fill(0);
    ellipse(14, -6, 3, 3);

    pop();
  }

  animate() {
    this.wingAngle += 0.2;

    if (this.isFlying) {
      this.x = this.baseX + sin(this.flyTimer) * 100;
      this.y = this.baseY + sin(this.flyTimer * 0.5) * 30;
      this.flyTimer += 0.04;
      if (this.flyTimer > TWO_PI * 2) {
        this.isFlying = false;
        this.x = this.baseX;
        this.y = this.baseY;
      }
    } else {
      this.y = this.baseY + sin(frameCount * 0.03) * 5;
    }
  }

  interact() {
    this.isFlying = true;
    this.flyTimer = 0;
  }

  contains(mx, my) {
    return dist(mx, my, this.x, this.y) < 35;
  }
}

class Flower {
  constructor(x, y, colorName) {
    this.x = x;
    this.y = y;
    this.colorName = colorName;
    this.stemHeight = 40;
    this.petalCount = 5;
    this.bloom = 0;
  }

  display() {
    push();
    translate(this.x, this.y);

    // Stem
    stroke(34, 139, 34);
    strokeWeight(3);
    line(0, 0, 0, -this.stemHeight);

    // Leaves
    noStroke();
    fill(50, 180, 50);
    ellipse(-10, -20, 15, 8);
    ellipse(10, -25, 15, 8);

    // Flower head
    translate(0, -this.stemHeight);

    let flowerColor;
    if (this.colorName === 'red') fill(255, 80, 80);
    else if (this.colorName === 'yellow') fill(255, 220, 50);
    else fill(255, 180, 200);

    for (let i = 0; i < this.petalCount; i++) {
      let angle = (TWO_PI / this.petalCount) * i;
      ellipse(cos(angle) * 10, sin(angle) * 10, 18, 18);
    }

    // Center
    fill(255, 220, 50);
    ellipse(0, 0, 12, 12);

    pop();
  }
}

class Tree {
  constructor(x, y) {
    this.x = x;
    this.y = y;
    this.trunkWidth = 30;
    this.trunkHeight = 80;
    this.foliageSize = 100;
  }

  display() {
    push();
    translate(this.x, this.y);

    // Trunk
    fill(139, 69, 19);
    noStroke();
    rect(-this.trunkWidth/2, -this.trunkHeight, this.trunkWidth, this.trunkHeight);

    // Foliage layers
    fill(34, 139, 34);
    ellipse(0, -this.trunkHeight - 30, this.foliageSize, this.foliageSize * 0.8);
    fill(50, 160, 50);
    ellipse(-25, -this.trunkHeight - 50, 70, 60);
    ellipse(25, -this.trunkHeight - 50, 70, 60);
    fill(30, 120, 30);
    ellipse(0, -this.trunkHeight - 70, 80, 50);

    pop();
  }
}

